class WebsiteReferenceExtraction(BaseModel):
    references: list[str]


class WebsiteReferenceCorrection(BaseModel):
    original_reference: str
    corrected_reference: str


class WebsiteReferenceCorrectionResult(BaseModel):
    corrections: list[WebsiteReferenceCorrection]


class PageSummaryResult(BaseModel):
    summary: str


existing_names = dir()

if "channels" in existing_names:
    available_channels = channels
else:
    available_channels = get_channels()

if "general" not in available_channels:
    raise ValueError("Channel 'general' not found")
if "random" not in available_channels:
    raise ValueError("Channel 'random' not found")

if "general_messages_data" in existing_names:
    channel_messages_data = general_messages_data
else:
    if "general_messages" in existing_names:
        channel_messages = general_messages
    else:
